import{_ as s,o as a,c as i,a4 as n}from"./chunks/framework.CtnSHCpE.js";const u=JSON.parse('{"title":"The package manager","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/ThePackageManager.md","filePath":"Guides/ThePackageManager.md","lastUpdated":1727668709000}'),t={name:"Guides/ThePackageManager.md"};function l(o,e,p,r,d,h){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="the-package-manager" tabindex="-1">The package manager <a class="header-anchor" href="#the-package-manager" aria-label="Permalink to &quot;The package manager&quot;">​</a></h1><h2 id="pre-requisites" tabindex="-1">Pre-requisites <a class="header-anchor" href="#pre-requisites" aria-label="Permalink to &quot;Pre-requisites&quot;">​</a></h2><p>Access to a z/OS UNIX machine with z/OS 2.4 and above and network connectivity to github.com and githubusercontent.com.</p><h2 id="installing-the-package-manager" tabindex="-1">Installing the package manager <a class="header-anchor" href="#installing-the-package-manager" aria-label="Permalink to &quot;Installing the package manager&quot;">​</a></h2><p>If you have curl and bash on your system, you can use this one liner:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bash -c &quot;$(curl -fsSL https://raw.githubusercontent.com/zopencommunity/meta/HEAD/tools/zopen_install.sh)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Otherwise, download the latest <a href="https://github.com/zopencommunity/metaport/releases" target="_blank" rel="noreferrer">meta pax</a> to z/OS</p><ul><li><p>download the file to your desktop</p></li><li><p>use <code>sftp</code> to upload the pax file to z/OS.</p></li><li><p>On z/OS, expand the pax using the command <code>pax -rvf &lt;filename&gt;.pax</code>.<br> This will expand the pax to the current directory, listing the various included files as it does so.</p></li><li><p>Source the .env to add <code>zopen</code> to your PATH:</p></li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./.env</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ul><li>Initialize your environment:</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Make sure to source the zopen-config file as instructed</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="using-the-package-manager" tabindex="-1">Using the package manager <a class="header-anchor" href="#using-the-package-manager" aria-label="Permalink to &quot;Using the package manager&quot;">​</a></h2><ul><li>Install any zopen community via <code>zopen install</code>, e.g.</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> which</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Installs which </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Now test which</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> which</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li>List which tools you have installed with <code>zopen list --installed</code>, e.g.</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --installed</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>See if any tools can be upgraded with <code>zopen list --upgradeable</code>, e.g.</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --upgradeable</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # list all tools that have upgrades available</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Upgrade your tools to the latest version with <code>zopen upgrade</code>, e.g.</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Set up your environment to use your installed tools by sourcing your environment, e.g.</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">zopen_roo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/etc/zopen-config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>List known security vulnerabilities in installed tools with <code>zopen audit</code>, e.g.</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> audit</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="package-collisions-with-z-os-unix-tools" tabindex="-1">Package Collisions with z/OS UNIX tools <a class="header-anchor" href="#package-collisions-with-z-os-unix-tools" aria-label="Permalink to &quot;Package Collisions with z/OS UNIX tools&quot;">​</a></h2><p>Packages such as <code>coreutils</code>, <code>gawk</code>, <code>sed</code>, <code>findutils</code>, <code>grep</code>, <code>diffutils</code>, <code>man-db</code> and <code>openssh</code> provide executables that collide with the z/OS UNIX tools under <code>/bin</code>.</p><h3 id="prefixing-for-zopen-community" tabindex="-1">Prefixing for zopen community <a class="header-anchor" href="#prefixing-for-zopen-community" aria-label="Permalink to &quot;Prefixing for zopen community&quot;">​</a></h3><p>To ensure seamless interaction with z/OS tools under <code>/bin</code>, z/OS Open tools that collide with a z/OS UNIX tool under <code>&lt;package&gt;/bin</code> will be prefixed as follows:</p><ul><li><strong><code>g</code> prefix</strong> for GNU-based tools (Coreutils, Awk, Findutils, Diffutils, Grep, Sed) . E.g., <code>gmake</code> and <code>gawk</code>.</li><li><strong><code>zot</code> prefix</strong> for non-GNU-based tools (Man-db, OpenSSH). E.g., <code>zotssh</code> and <code>zotman</code></li></ul><p>Tools that have collisions will also print out an install caveat during zopen install.</p><p>The original unprefixed binaries will be placed under <code>&lt;package&gt;/altbin</code>.</p><h3 id="using-tools-without-prefix" tabindex="-1">Using Tools without Prefix <a class="header-anchor" href="#using-tools-without-prefix" aria-label="Permalink to &quot;Using Tools without Prefix&quot;">​</a></h3><p>If you prefer to use the tools without the prefix, you can specify the <code>--override-zos-tools</code> option when sourcing <code>zopen-config</code> as follows:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">zopen_roo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/etc/zopen-config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --override-zos-tools</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Alternatively, you can add <code>$ZOPEN_ROOTFS/usr/local/altbin</code> to your $PATH.</p><h3 id="adjusting-the-default-override-mode-for-your-zopen-installation" tabindex="-1">Adjusting the default override mode for your zopen installation <a class="header-anchor" href="#adjusting-the-default-override-mode-for-your-zopen-installation" aria-label="Permalink to &quot;Adjusting the default override mode for your zopen installation&quot;">​</a></h3><p>zopen init provides the following option which can adjust the default override mode.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  --[no]override-zos-tools</span></span>
<span class="line"><span>          Toggle default mode for overriding z/OS /bin tools</span></span>
<span class="line"><span>          in the zopen-config. Default is --nooverride-zos-tools</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>For examples:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --override-zos-tools</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you have a zopen fileystem already configured, you can use the <code>zopen config</code> command to set the value:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> override_zos_tools</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --refresh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # to refresh the zopen-config file</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="selecting-a-specific-set-of-packages-to-override" tabindex="-1">Selecting a Specific Set of Packages to Override <a class="header-anchor" href="#selecting-a-specific-set-of-packages-to-override" aria-label="Permalink to &quot;Selecting a Specific Set of Packages to Override&quot;">​</a></h3><p>If you want to override only a specific set of packages, you can create a file that lists the packages you want to override. This allows for more fine-grained control over which packages are overridden.</p><p><strong>Creating the override list file</strong></p><ul><li>Create a file named <code>zopen.subset</code> in your home directory ($HOME/zopen.subset). Add one tool per line to the file, without any leading or trailing whitespace. For example:</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gawk</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">coreutils</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>When sourcing zopen-config, use the <code>--override-zos-tools-subset</code> option followed by the path to your zopen.subset file:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>. $ZOPEN_ROOTFS/etc/zopen-config --override-zos-tools-subset $HOME/zopen.subset</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This will override only the packages listed in the zopen.subset file.</p><p><strong>Format of the override list file</strong></p><ul><li>One tool per line</li><li>No leading or trailing whitespace</li><li>Names must match the package names (e.g., gawk, coreutils, sed)</li></ul><h1 id="upgrading-the-meta-zopen-package-manager" tabindex="-1">Upgrading the meta zopen package manager <a class="header-anchor" href="#upgrading-the-meta-zopen-package-manager" aria-label="Permalink to &quot;Upgrading the meta zopen package manager&quot;">​</a></h1><p>The meta package, which include zopen, can be upgraded via the <code>zopen upgrade</code> command as follows:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> zopen upgrade meta</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Note:</strong> If you have an older version of meta (&lt;=0.6.3), you will need to remove the .pinned file from your zopen file system:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> find $zopen_rootfs -name </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.pinned&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Use rm to remove .pinned entries.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h1 id="signing-verifying-using-zopen-framework" tabindex="-1">Signing &amp; verifying using zopen framework <a class="header-anchor" href="#signing-verifying-using-zopen-framework" aria-label="Permalink to &quot;Signing &amp; verifying using zopen framework&quot;">​</a></h1><ul><li><p><code>zopen-build</code> can now generate signed builds, and <code>zopen-install</code> can verify the signature before installation.</p></li><li><p>We can enable signed builds using the <code>--sign-pax</code> or <code>-sp</code> option. If this option is set, it reads the <strong>ZOPEN_GPG_SECRET_KEY_FILE</strong> and its passphrase from <strong>ZOPEN_GPG_SECRET_KEY_PASSPHRASE_FILE</strong> to sign the file. The public key is read from <strong>ZOPEN_GPG_PUBLIC_KEY_FILE</strong>. <br>These files are mandatory for signing a file.</p></li><li><p>The public key and the signed file details are written to metadata.json (this JSON is not part of the PAX).</p></li><li><p>During installation, the signed file will be verified against the signature and public key. Not recommended: If you prefer to bypass verification of signed PAX files, specify <code>--skip-verify</code>.</p></li></ul>`,59)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
